import React from 'react';
import { Button, ButtonProps } from '@mui/material';
import GetAppRoundedIcon from '@mui/icons-material/GetAppRounded';
import { EnvConfig } from '@/constants/EnvConfig';
import { requestPwaInstall } from '@/components/PWAInstallPrompt';

const isStandalone = (): boolean => {
    if (typeof window === 'undefined') return false;
    const navAny = window.navigator as Navigator & { standalone?: boolean };
    return (
        window.matchMedia('(display-mode: standalone)').matches ||
        window.matchMedia('(display-mode: fullscreen)').matches ||
        window.matchMedia('(display-mode: minimal-ui)').matches ||
        navAny.standalone === true
    );
};

/**
 * Glass-morphism pill button that opens the global PWA install dialog
 * (rendered by `<PWAInstallPrompt />` in main.tsx) via a custom window event.
 *
 * Hidden when the app is already installed / running standalone, so it
 * never appears inside the installed app.
 */
export const InstallAppButton: React.FC<ButtonProps> = (props) => {
    const [hidden, setHidden] = React.useState<boolean>(true);

    React.useEffect(() => {
        setHidden(isStandalone());
        const onInstalled = () => setHidden(true);
        window.addEventListener('appinstalled', onInstalled);
        return () => window.removeEventListener('appinstalled', onInstalled);
    }, []);

    if (hidden) return null;

    return (
        <Button
            variant='outlined'
            onClick={requestPwaInstall}
            startIcon={<GetAppRoundedIcon fontSize='small' sx={{ color: 'inherit' }} />}
            aria-label={`Install ${EnvConfig.SiteName} app`}
            {...props}
            sx={{
                height: 40,
                px: 2.25,
                gap: 1,
                borderRadius: 999,
                textTransform: 'none',
                fontSize: '0.85rem',
                fontWeight: 600,
                color: 'primary.main',
                bgcolor: 'rgba(255, 255, 255, 0.7)',
                border: '1.5px solid',
                borderColor: 'primary.main',
                backdropFilter: 'blur(8px)',
                WebkitBackdropFilter: 'blur(8px)',
                boxShadow: '0 6px 18px -8px rgba(21, 101, 192, 0.25)',
                transition: 'background 180ms ease, border-color 180ms ease, color 180ms ease, transform 120ms ease, box-shadow 200ms ease',
                '& .MuiButton-startIcon': {
                    color: 'inherit',
                    marginRight: 0.5,
                },
                '& .MuiButton-startIcon svg': {
                    color: 'inherit',
                    fill: 'currentColor',
                },
                '&:hover': {
                    bgcolor: '#fff',
                    color: 'primary.dark',
                    borderColor: 'primary.dark',
                    boxShadow: '0 10px 24px -10px rgba(21, 101, 192, 0.4)',
                },
                '&:active': {
                    transform: 'translateY(1px)',
                },
                '&:focus-visible': {
                    outline: '2px solid',
                    outlineColor: 'primary.main',
                    outlineOffset: 2,
                },
                ...(props.sx ?? {}),
            }}
        >
            Install {EnvConfig.SiteName}
        </Button>
    );
};

